// src/statusline.ts
function formatLspStatus(counts, fg, hasDiagnostics2 = false) {
  const { running, starting, error } = counts;
  if (running === 0 && starting === 0 && error === 0) {
    return;
  }
  const label = hasDiagnostics2 ? `${fg("error", "⚡")}${fg("accent", "LSP")}` : fg("accent", "⚡LSP");
  const parts = [label];
  if (starting > 0) {
    parts.push(fg("dim", `…${starting}`));
  }
  if (error > 0) {
    parts.push(fg("error", `✕${error}`));
  }
  return parts.join(" ");
}

